-- Enrichment marathon batch: DISCO, Discord, Discount Bandit, Discourse, dittofeed, Dixa, Django-CRM, Docassemble

-- ── DISCO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-native, AI-powered legal ediscovery and case management platform helping law firms, corporations, and government agencies review, analyze, and manage litigation data.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Usage-based (per-GB hosting)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$500-1,000 employees (publicly traded, NYSE: LAW)$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$DISCO Review 2026: AI eDiscovery Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$DISCO is a cloud-native, AI-powered eDiscovery and legal review platform. Explore DISCO's per-GB pricing, Cecilia AI features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$DISCO, formally CS Disco, Inc. and traded on the New York Stock Exchange under the ticker LAW, is a cloud-native, artificial-intelligence-powered legal technology platform focused on ediscovery, document review, and case management for litigation and investigations. The company was founded in 2013 by Kiwi Camara together with co-founders Kent Radford, Kevin Smith, and Gabe King, initially in Houston, Texas, before the company relocated its headquarters to Austin, Texas, where it remains based today. DISCO went public in July 2021, raising roughly $224 million in its IPO, and now operates as a publicly traded enterprise software company with an estimated 500 to 1,000 employees across a dozen or so locations. From its earliest days, DISCO positioned itself against legacy ediscovery vendors by building a browser-based, cloud-native architecture rather than relying on on-premises installations, which was unusual for the legal technology industry at the time and became a core differentiator as law firms and corporate legal departments shifted to remote and hybrid work. The platform's product architecture spans several integrated modules that together cover the litigation lifecycle. DISCO Hold automates legal hold notices and data preservation, helping legal teams meet compliance obligations when litigation is reasonably anticipated. DISCO Ediscovery handles the ingestion, processing, and early case assessment of large volumes of electronically stored information, using deduplication and near-duplicate detection to reduce the amount of data that must be reviewed and billed. DISCO Review is the AI-driven document review engine where the bulk of attorney and paralegal time is spent, offering predictive coding, technology-assisted review (TAR), and search tools designed to accelerate first-pass review. DISCO Case Builder centralizes case data, deposition transcripts, and exhibits so litigation teams can collaboratively build narratives and trial materials from within the same environment used for review. A defining feature of the modern DISCO platform is Cecilia, its generative-AI assistant, which is built directly into the review workflow rather than offered as an add-on; specific Cecilia capabilities highlighted in DISCO's marketing include Cecilia Q&A for querying case data in natural language, Auto Timelines that reconstruct chronological event sequences from case documents automatically, and Deposition Summaries that condense deposition transcripts into digestible summaries for attorneys. This AI-first product strategy is DISCO's primary competitive positioning relative to older-generation ediscovery platforms that bolted AI features onto legacy review tools after the fact. On the commercial side, DISCO differentiates itself with a flat-rate, per-gigabyte pricing model rather than the more fragmented line-item billing (processing fees, hosting fees, user fees, review-tool fees) that has historically characterized the ediscovery industry. Public pricing materials describe a per-GB hosting fee that covers access to Active Review, early case assessment (ECA) tools, and the advanced AI features such as Cecilia Q&A, Auto Timelines, and Deposition Summaries, with deduplicated data excluded from billing at the global family level so customers are not charged twice for duplicate documents. Beyond the per-GB hosting charge, DISCO also offers around-the-clock project management services, billed separately at a rate of approximately $250 per hour, in which DISCO's professional services staff help law firms and corporate legal teams design and execute review strategies. Because DISCO does not publish a single flat starting price and pricing ultimately depends on data volume, matter complexity, and the mix of services selected, prospective customers typically need to request a custom quote; this is standard practice across the ediscovery software category, where costs scale directly with the amount of data under review. User reviews on platforms like G2 consistently praise DISCO's interface as more modern and user-friendly than competing ediscovery tools, and reviewers frequently cite the predictability of flat per-GB pricing as a meaningful advantage over vendors that nickel-and-dime clients with separate charges for processing, hosting, and review seats. Support quality is also highlighted positively, with users noting responsive email, chat, and phone support during active matters. On the other hand, some reviewers note that law firms can find it operationally difficult to pass DISCO's usage-based costs through to their own clients in a granular way, since traditional legal billing practices are not always built around per-gigabyte software costs; DISCO has reportedly been working on improving usage-data reporting to make this pass-through easier. DISCO's target customers are litigation-focused law firms of all sizes, corporate legal and compliance departments handling internal investigations or regulatory response, legal services providers, and government agencies that need to process, review, and produce electronically stored information for litigation, investigations, or public records requests. Because DISCO is purpose-built for legal workflows, it competes primarily with other dedicated ediscovery and legal review platforms rather than general-purpose document management tools. Its most direct competitors include Relativity (the long-standing market leader in enterprise ediscovery), Reveal (formerly Logikcull), Everlaw, and Nextpoint, all of which similarly combine data processing, AI-assisted review, and case management in cloud-hosted platforms aimed at the legal market. DISCO differentiates itself within this competitive set primarily through its AI-native Cecilia features, simplified per-GB pricing, and a design philosophy oriented toward ease of use for both technical litigation-support staff and practicing attorneys who are not necessarily technology specialists. As a public company, DISCO also publishes quarterly financial results, and its revenue growth and profitability trajectory as a SaaS-model legal technology vendor are followed by financial analysts covering the broader legal tech and vertical SaaS software sectors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '046d5368-1873-461f-9ac4-29a6afeb6d0a';

