-- ── Discord ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Voice, video, and text chat platform organized into communities called servers, used by gamers, creators, and businesses for real-time communication.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Nitro from $2.99/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~700-900 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Japanese$q$, $q$Korean$q$, $q$Chinese$q$, $q$Russian$q$, $q$Italian$q$, $q$Polish$q$, $q$Turkish$q$, $q$Arabic$q$, $q$Dutch$q$, $q$Vietnamese$q$, $q$Thai$q$]::text[],
  seo_title = COALESCE($q$Discord Review 2026: Features, Pricing & Nitro Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Discord is a free voice, video, and text chat platform for communities and gamers. See how Discord works, Nitro pricing tiers, key features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Discord is a voice, video, and text communication platform organized around persistent communities called servers, each of which can be subdivided into topic-specific text and voice channels. Publicly released in May 2015, Discord was created by Jason Citron and Stanislav Vishnevskiy, who first met while building Hammer & Chisel, a game studio Citron founded (originally called Phoenix Guild) after selling his earlier company, the social gaming network OpenFeint, to GREE for roughly $104 million in 2011. Hammer & Chisel's mobile game Fates Forever included built-in voice and text chat, and it was the frustration of Citron's own team with unreliable third-party voice-chat software during development that led directly to the creation of Discord as a dedicated, low-latency communication tool for gamers. The product quickly outgrew its gaming-only origins and became a general-purpose community platform used by hobbyist groups, creators, open-source projects, students, and businesses, though gaming remains central to its identity and user base; Discord has reported that more than 90 percent of its users play video games and that a large share of PC players start a game within an hour of logging in. Discord is headquartered in San Francisco, California, and has scaled significantly since its 2015 launch: the company has cited more than 200 million monthly active users at various points and reported roughly 90 million or more daily active users by late 2025. Employee headcount grew roughly fivefold between 2020 and 2024 before the company laid off about 17 percent of staff, or roughly 170 people, in January 2024 as part of a broader effort to focus its roadmap; current headcount is estimated in the 700 to 900 range. In a significant leadership change, founder Jason Citron stepped down as CEO in April 2025, moving to the board of directors and an advisory role, and was succeeded by Humam Sakhnini, a veteran of Activision Blizzard and King with deep experience in the games industry. Discord's core architecture centers on servers (also called guilds), which are self-organized communities that owners and moderators configure with text channels, voice channels, threads, and, more recently, Stages for structured audio events and Activities for embedded mini-games and shared experiences playable directly inside a voice channel. The platform supports direct messages, group DMs, screen sharing, video calls, and a large ecosystem of third-party bots and integrations built on Discord's public API, which developers use to add moderation tools, music playback, games, and workflow automation to individual servers. Discord's monetization strategy is built on a freemium model: the core chat, voice, and video functionality is free for all users, and revenue comes primarily from Discord Nitro, a subscription introduced in 2017 that unlocks features such as higher-quality video streaming (up to 4K), larger file upload limits (500MB versus the free tier's much lower cap), animated avatars and custom emoji usable across any server, and monthly Server Boost credits that unlock perks like better audio quality and more custom emoji options for a chosen community. As of the current pricing structure, Discord offers two paid tiers: Nitro Basic at $2.99 per month (or $29.99 annually) for a lighter set of perks, and full Nitro at $9.99 per month (or $99.99 annually) which adds two free Server Boosts, animated avatars, 4K streaming, and higher upload limits; annual billing saves roughly 17 percent compared to paying monthly. Discord also offers localized pricing in numerous currencies and countries, including Brazil, Turkey, Poland, Australia, Japan, Mexico, the UK, Canada, and South Korea, among others. Server Boosting itself can also be purchased directly by community members who want to upgrade a specific server's perks without necessarily subscribing to personal Nitro. Discord's target users span individual gamers and friend groups, content creators and streamers building fan communities, open-source and developer communities, students and study groups, and, increasingly, businesses and brands running community or support channels. Its closest competitors depend on use case: for gaming and informal community chat, alternatives include the now-defunct Guilded and platforms like Steam Chat; for broader team and community communication it is sometimes compared to Slack and Microsoft Teams (though those are oriented toward workplace collaboration rather than public communities); and for large-scale public community hosting it competes conceptually with Reddit and Telegram groups. Notable facts about Discord's business trajectory include a 2021 funding round that valued the company at roughly $15 billion, led by investors including Baillie Gifford, alongside widely reported acquisition interest from larger technology companies that Discord ultimately did not accept, reinforcing its strategy of remaining an independent, standalone communications platform. Discord is available as native apps for Windows, macOS, Linux, iOS, and Android, as well as through a web browser client, giving it broad cross-platform reach that has helped cement it as one of the dominant real-time chat platforms among younger, gaming-adjacent internet users worldwide.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7';

