-- ── Discourse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source community forum and discussion platform, free to self-host or available as managed hosting, used by companies and communities for forums and support.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (Free open-source self-hosted; hosted plans from $100/month)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted) / $100/month (hosted Pro)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$~200-215 employees$q$, company_size),
  headquarters = COALESCE($q$El Cerrito, California, USA (fully remote team)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Italian$q$, $q$Japanese$q$, $q$Chinese$q$, $q$Russian$q$, $q$Dutch$q$, $q$Polish$q$, $q$Turkish$q$, $q$Korean$q$, $q$Arabic$q$]::text[],
  seo_title = COALESCE($q$Discourse Review 2026: Pricing, Features & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Discourse is an open-source forum platform, free to self-host or hosted from $100/month. Compare Discourse pricing, features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Discourse is an open-source community discussion and forum platform built by Civilized Discourse Construction Kit, Inc. (commonly abbreviated CDCK), founded in 2013 by Jeff Atwood, Robin Ward, and Sam Saffron. Jeff Atwood is widely known in the software industry as the co-founder of Stack Overflow and the broader Stack Exchange network, and he started Discourse with the explicit goal of modernizing online discussion software, which he felt had stagnated compared to the design and moderation standards achievable with modern web technology. The company raised early funding from well-known technology investors including First Round Capital, Greylock Partners, and SV Angel, reportedly including a $20 million Series A round, reflecting strong investor confidence in the open-source discussion platform model at a time when most competing forum software was either aging proprietary systems (like vBulletin) or older open-source projects (like phpBB) that had not meaningfully modernized. Discourse is headquartered in El Cerrito, California, and operates as a fully remote company with employees distributed across five continents; estimates place its current headcount at roughly 200 to 215 employees, with reported annual revenue in the range of $10 million to $50 million, generated primarily through its hosting and enterprise services business built on top of the free open-source core. Architecturally, Discourse is built with a Ruby on Rails backend and an Ember.js single-page-application frontend, with real-time updates delivered via WebSockets, giving it a fast, modern, chat-like feel that differentiates it from older forum software built around full-page reloads. The platform is fully open source under a GPL-family license and can be self-hosted for free using Docker, which is the officially supported and recommended installation method; this makes Discourse popular among open-source projects, developer communities, and organizations with strict data-residency or budget requirements that want complete control over their community infrastructure. Feature-wise, Discourse organizes discussions into categories and tags, uses a trust-level system with gamification elements (badges, likes, and reputation) to encourage constructive participation and gradually grant more permissions to established community members, and supports single sign-on via OAuth2, OpenID Connect, and SAML for enterprise identity integration. In 2023, Discourse added a native real-time Chat feature, blurring the line between traditional threaded forums and modern chat platforms and allowing communities to offer both asynchronous long-form discussion and synchronous real-time conversation within the same product. The platform also has an extensive plugin and theme ecosystem, with dozens of official and community plugins covering everything from polls and calendars to e-commerce and moderation tooling, and it exposes a full API and webhook system for custom integrations. More recently, Discourse has introduced Discourse AI, a first-party plugin suite that adds AI-powered features such as automatic topic summarization, sentiment analysis, smart replies, and AI-assisted content moderation, reflecting the broader industry shift toward embedding large language model capabilities directly into existing collaboration software. On pricing, Discourse follows a classic open-core and hosted-SaaS model. Self-hosting the software is entirely free, with no licensing fees, since Discourse is open source; organizations that self-host are responsible for their own server infrastructure, Docker deployment, and maintenance. For organizations that prefer managed hosting, Discourse offers tiered hosted plans: a free tier for exploring the platform with limited resources (roughly 500,000 monthly page views, 5GB storage, 20,000 monthly emails, and 2 staff seats); a Pro tier at $100 per month with unlimited members and chat, unlimited categories and tags, custom themes, a custom domain, API and webhook access, access to 15 or more plugins, and 5 staff seats; a Business tier at $500 per month adding advanced reporting and analytics, workflow automation, event functionality, gamification, SSO via OpenID and OAuth2, 20 or more additional plugins, 15 staff seats, and priority support; and a custom-priced Enterprise tier that adds expert design and development services, a 99.9 percent uptime guarantee, GDPR and CCPA-compliant hosting, 50 or more plugins, and unlimited staff seats. Resource limits such as storage, monthly emails, and AI feature credits scale up meaningfully across these tiers, giving growing communities a clear upgrade path. As of a few years after launch, Discourse's official hosting business reportedly served around 600 paying hosting customers generating roughly $120,000 per month in revenue with reported year-over-year doubling in its early growth phase, and by 2022 more than 3,000 businesses and community instances had adopted Discourse's official SaaS hosting. Discourse's target customers span open-source software projects seeking a modern community forum (it is used by many well-known open-source projects), SaaS and technology companies building customer or developer support communities, hardware and gaming communities, and general-interest online communities migrating away from legacy forum software or from closed platforms like Facebook Groups and Reddit where they have less control over data and moderation. Its primary competitors include other modern hosted community platforms such as Circle and Khoros, more traditional open-source forum alternatives like Flarum and phpBB, and adjacent product-support-focused community tools like Zendesk Community and Vanilla Forums, though Discourse differentiates itself through its combination of full open-source availability, modern real-time architecture, and a credible, well-funded team with deep experience building large-scale online discussion products.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6b5b1e4-ac40-42b0-bab2-d22554c5ce08';

