-- ── dittofeed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, developer-friendly customer engagement platform for building omnichannel messaging journeys across email, SMS, push, WhatsApp, and Slack.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (Free self-hosted open-source; Cloud Pro from $75/month)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted) / $75/month (Cloud Pro)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Small team (Y Combinator S22-backed startup)$q$, company_size),
  headquarters = COALESCE($q$Los Angeles, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Dittofeed Review 2026: Open-Source Engagement Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Dittofeed is an open-source customer engagement platform for email, SMS, push, and WhatsApp journeys. Compare Dittofeed's self-hosted and Cloud Pro pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Dittofeed is an open-source, developer-friendly customer engagement platform designed for building automated, omnichannel messaging journeys and one-off broadcast campaigns across email, SMS, mobile push notifications, WhatsApp, and Slack. The company was founded in 2022 by Chandler Craig and Maxwell Gurewitz, who went through Y Combinator's Summer 2022 (S22) batch, and is headquartered in Los Angeles, California. The founders' backgrounds are directly relevant to the product they built: Maxwell Gurewitz previously worked as a senior software engineer at OpenTable and at Braze, one of the leading commercial customer engagement platforms, where he helped architect infrastructure for automated messaging services, giving him first-hand experience with the technical challenges of building reliable, high-scale messaging systems. Chandler Craig previously worked in marketing roles at Sony Music and at various business-to-consumer startups, giving the founding team a combination of deep backend messaging infrastructure expertise and hands-on marketing operator experience with the kinds of campaigns and journeys such a platform needs to support. Dittofeed's explicit mission is to build a great open-source alternative to established commercial customer engagement and marketing automation platforms such as Klaviyo, Braze, Customer.io, OneSignal, Segment Engage, and Mailchimp, all of which are closed-source, proprietary SaaS products that can become expensive at scale and that require customers to hand over their customer data entirely to a third-party vendor. By contrast, Dittofeed publishes its full source code publicly on GitHub and supports self-hosted deployment via Docker or platforms like Render, meaning organizations that prioritize data ownership, compliance, or cost control can run the entire platform on their own infrastructure at no licensing cost. Architecturally, Dittofeed centers on a visual journey builder that lets marketing and growth teams design automated, multi-step messaging workflows triggered by user behavior or events, alongside a broadcast campaign feature for one-off sends, a user segmentation engine for targeting specific audience groups, and an integrations library that connects to common data and delivery infrastructure such as Segment, Twilio, and SendGrid. Being open source and API/SDK-first, Dittofeed is explicitly positioned for developer-led marketing and growth teams who want to trigger messages programmatically based on product events, rather than relying solely on a marketing team manually configuring campaigns through a UI, though the platform does provide a UI-based journey and segment builder as well. On the commercial side, Dittofeed follows an open-core business model with several distinct offerings. The fully self-hosted, open-source version of the core platform is free with no licensing fee, requiring only that a company run and maintain its own infrastructure. For organizations that want Dittofeed's hosting without the operational burden of self-hosting, the company offers Cloud Pro at $75 per month, which includes up to 10,000 monthly unique users, full access to the integrations library, and marketing plus transactional automation, with a 14-day free trial; usage beyond the included 10,000 users is billed on a tiered per-user basis, at $0.004 per user for the next tier up to 100,000 users, $0.002 per user from 100,001 to 500,000 users, and $0.001 per user beyond 500,000 users, giving the pricing model a clear, transparent path for growing companies. Above Cloud Pro, Dittofeed offers custom-priced Enterprise plans in two flavors: an Enterprise Self-Hosted License, which adds multi-tenant advanced authentication, the full integrations library, white-labeling, embeddable components, and priority support to a self-hosted deployment; and an Enterprise Cloud License, which bundles all of the same self-hosted enterprise features together with Dittofeed's own hosting. A separate Support Pro add-on is also available at custom pricing, providing dedicated Slack Connect access, prioritized feature-request development, faster response times, biweekly video calls, and hands-on implementation assistance for building out journeys, segments, and message templates. Dittofeed's target customers are primarily startups and growth-stage companies, particularly those with in-house engineering resources, who want the flexibility and cost control of an open-source platform without sacrificing the sophistication of journey automation and multi-channel delivery offered by larger incumbents. It is especially attractive to companies with strict data residency, security, or compliance requirements that make sending all customer data to a third-party SaaS vendor undesirable, since self-hosting keeps customer data entirely within a company's own infrastructure. Competitors in the customer engagement and marketing automation space include Customer.io, Braze, OneSignal, Klaviyo, and Segment's Engage product, as well as smaller developer-oriented notification infrastructure tools like Novu and Courier, though Dittofeed differentiates itself specifically through its combination of a fully open-source core, transparent usage-based Cloud pricing, and a founding team with direct prior experience building messaging infrastructure at Braze. Because Dittofeed emerged from Y Combinator and has been publicly noted as raising funding through a convertible note rather than a large priced round, it remains a comparatively small, early-stage company relative to well-established incumbents in this category, which is reflected in its smaller integrations library and support footprint but is offset by its rapid open-source development pace and responsiveness to community and customer feature requests.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c39707a3-e756-48c8-929c-f10fe278ae92';

