-- ── Dixa ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based customer service platform unifying phone, email, chat, and social channels into one conversation view, with AI agent automation for support teams.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-agent/month)$q$, pricing_model),
  starting_price = COALESCE($q$€89/agent/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~158-160 employees$q$, company_size),
  headquarters = COALESCE($q$Copenhagen, Denmark$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Danish$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Swedish$q$, $q$Norwegian$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$Dixa Review 2026: Pricing, Features & AI Agent Mim$q$, seo_title),
  seo_meta_description = COALESCE($q$Dixa is a Copenhagen-based omnichannel customer service platform with an AI agent (Mim). See Dixa's pricing tiers from €89/agent/month, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Dixa is a cloud-based customer service and helpdesk platform founded in 2015 in Copenhagen, Denmark, by Mads Fosselius (who serves as CEO), Krisztian Tabori, Jakob Nederby Nielsen, and Jacob Vous Petersen. The company built its platform around the concept of unifying customer conversations across phone, email, live chat, social media, and web forms into a single, continuous timeline per customer, rather than treating each channel as a separate ticketing silo the way many earlier-generation helpdesk tools did; Dixa originally marketed this approach under the phrase 'customer friendship' and has since repositioned itself around agentic AI, describing itself as an agentic AI customer service platform. Dixa has raised substantial venture funding since its founding, starting with a $14 million Series A led investors reported by TechCrunch in February 2019, followed by a €32.5 million (approximately $36 million) Series B round announced in February 2020, and culminating in a $105 million Series C round in July 2021 led by General Atlantic, bringing the company's total disclosed funding to roughly $158 to $164 million across multiple rounds from investors including General Atlantic, Notion Capital, Project A Ventures, and Seed Capital. The company operates from offices in Copenhagen and London and, as of mid-2026, has an estimated headcount in the range of 158 to 161 employees, having scaled down somewhat from a peak of around 242 employees in 2021 as the company matured and focused its operations. Dixa states that it serves more than 1,000 ecommerce and direct-to-consumer brands across 42 countries, reflecting a customer base heavily weighted toward online retail and consumer brands that need to manage high support volumes across many channels simultaneously. Product-wise, Dixa's platform is built around a unified agent workspace that brings phone (including built-in contact center functionality with intelligent routing and IVR), email, live chat, social media messaging, and web-based contact forms into one interface, so that a support agent handling a customer's issue can see the full history of that customer's prior interactions regardless of which channel they originally came in on. Key platform capabilities include intelligent routing and interactive voice response (IVR) for phone support, call recording and customer callback scheduling, a built-in knowledge base for self-service and agent reference, service-level agreement (SLA) tracking, and native integrations with more than 35 third-party tools commonly used by ecommerce and DTC brands, such as Shopify and Klaviyo. A central pillar of Dixa's current product strategy is Mim, its AI agent, which is designed to autonomously handle and resolve customer inquiries rather than simply assisting human agents; Mim is priced separately from the core per-agent subscription, on a flat usage-based rate described as roughly €0.35 per conversation regardless of whether the AI successfully resolves the issue, which differs from some AI customer service competitors that charge only for successful automated resolutions. Dixa's core subscription pricing is structured around three published per-agent, per-month tiers, billed in euros or British pounds with a roughly 20 percent discount for annual billing compared to monthly billing. The entry-level Growth plan is priced at €89 per agent per month and includes the core contact center functionality (phone, email, chat, social, and forms), a knowledge base, the Mim AI agent, intelligent routing and IVR, call recording and customer callback, SLA tracking, and native integrations with Shopify, Klaviyo, and more than 35 other tools. The mid-tier Ultimate plan, at €139 per agent per month, adds routing based on external data sources, knowledge-centered service AI capabilities, standard AI intent detection, more advanced automation and skills-based routing, and sandbox access along with third-party AI integrations. The top published tier, Prime, at €179 per agent per month and described by Dixa as its most popular plan, adds single sign-on (SSO), advanced AI intent detection, advanced AI-powered insights and analytics, custom user roles, support for multiple organizations within one account, queue and claim restrictions, and higher enterprise API rate limits. Beyond these core tiers, Dixa offers several optional add-ons priced separately, including an AI Co-Pilot that uses generative AI to help agents draft and translate responses, a quality assurance module for real-time conversation monitoring and coaching, voice transcription, and advanced analytics and insights, along with seasonal agent pricing options for businesses that need to scale support staff up and down around peak periods such as holiday shopping seasons. Dixa's target customers are primarily mid-market to enterprise companies, with a particular concentration in ecommerce and direct-to-consumer retail brands that need to manage support across phone, chat, email, and social channels simultaneously and that value tight integration with commerce platforms like Shopify. Its main competitors in the customer service and helpdesk software category include Zendesk, Intercom, Freshdesk, Kustomer, Gorgias (which is especially focused on ecommerce and Shopify-native support, similar to Dixa's core market), and Front, with Dixa differentiating itself primarily through its native AI agent Mim, its unified conversation-timeline architecture, and its published, transparent per-agent pricing structure, which stands in contrast to some competitors that require a sales call to obtain any pricing information at all.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8a056723-ee4b-46ab-988f-3d80d7a96c4e';

