INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Cecilia AI Assistant$q$, $q$Generative-AI assistant embedded in the review workflow, offering natural-language Q&A over case data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Auto Timelines$q$, $q$Automatically reconstructs chronological event sequences from case documents to speed up case analysis.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Deposition Summaries$q$, $q$AI-generated condensed summaries of deposition transcripts for faster attorney review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$DISCO Hold$q$, $q$Automates legal hold notices and data preservation to help teams meet compliance obligations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$DISCO Ediscovery$q$, $q$Cloud-native ingestion, processing, and early case assessment of electronically stored information.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$DISCO Review$q$, $q$Predictive coding and technology-assisted review (TAR) tools for accelerating document review.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$DISCO Case Builder$q$, $q$Centralizes case data, deposition transcripts, and exhibits for collaborative trial preparation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Flat Per-GB Pricing$q$, $q$Transparent, predictable per-gigabyte hosting fee instead of fragmented line-item billing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$User-friendly, modern interface compared to legacy ediscovery tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Predictable flat per-GB pricing instead of fragmented fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$AI-native review tools (Cecilia) built directly into the workflow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Highly rated, responsive customer support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$No published flat starting price; costs scale with data volume and require a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Some firms find it operationally difficult to pass usage-based costs through to clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Purpose-built for legal workflows only, not a general-purpose document platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Project management services are billed separately at an hourly rate$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$What is DISCO used for?$q$, $q$DISCO is used for legal ediscovery, AI-assisted document review, legal hold management, and case building during litigation, investigations, and regulatory response.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Is DISCO publicly traded?$q$, $q$Yes. CS Disco, Inc. trades on the New York Stock Exchange under the ticker symbol LAW after its July 2021 IPO.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$How is DISCO priced?$q$, $q$DISCO uses a flat-rate, per-gigabyte hosting fee that covers Active Review, early case assessment, and AI features, plus optional project management services billed at roughly $250 per hour.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$What is Cecilia?$q$, $q$Cecilia is DISCO's generative-AI assistant, embedded in the review workflow to power natural-language Q&A, automatic timeline reconstruction, and deposition summarization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Who are DISCO's main competitors?$q$, $q$DISCO competes primarily with Relativity, Reveal (formerly Logikcull), Everlaw, and Nextpoint in the cloud ediscovery and legal review market.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Who founded DISCO?$q$, $q$DISCO was founded in 2013 by Kiwi Camara along with co-founders Kent Radford, Kevin Smith, and Gabe King, originally in Houston, Texas.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Litigation Document Review$q$, $q$Law firms use DISCO to process, search, and review large volumes of electronically stored information for active litigation.$q$, $q$Litigation law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Corporate Investigations & Compliance$q$, $q$Corporate legal departments use DISCO Hold and Review to manage internal investigations, regulatory response, and preservation obligations.$q$, $q$Corporate legal and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Government Records & Litigation Response$q$, $q$Government agencies use DISCO to process and produce electronically stored information for litigation or public records requests.$q$, $q$Government legal departments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Per-GB Hosting$q$, $q$Custom (billed per gigabyte)$q$, $q$Usage-based / Monthly$q$, NULL, $q$["Active Review access","Early case assessment (ECA)","Cecilia Q&A, Auto Timelines, Deposition Summaries","Deduplication at the family level excluded from billing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$Project Management Services$q$, $q$~$250/hour$q$, $q$Hourly, add-on$q$, NULL, $q$["Dedicated project management staff","Review strategy design","Around-the-clock availability"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DISCO (CS Disco, Inc., NYSE: LAW) is a cloud-native, AI-powered legal technology platform built for ediscovery, document review, and case management. Founded in 2013 in Houston and now headquartered in Austin, Texas, DISCO went public in 2021 and has grown into a publicly traded vendor serving law firms, corporate legal departments, legal services providers, and government agencies.$q$, $q$The platform's core pitch is that legal discovery does not need to be slow, opaque, or billed through a maze of line-item fees. DISCO combines data processing, technology-assisted review, and AI features into a single browser-based product with transparent per-gigabyte pricing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DISCO's product suite includes DISCO Hold for automated legal hold and data preservation, DISCO Ediscovery for processing and early case assessment, DISCO Review for AI-assisted document review, and DISCO Case Builder for organizing case materials and building trial narratives.$q$, $q$Its generative-AI assistant, Cecilia, is embedded directly into the review workflow and powers features such as Cecilia Q&A for natural-language queries over case data, Auto Timelines that reconstruct chronologies automatically, and Deposition Summaries that condense transcripts for faster attorney review.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DISCO uses a flat-rate, per-gigabyte pricing model rather than the fragmented processing, hosting, and per-seat fees common among older ediscovery vendors. Deduplicated data at the family level is excluded from charges, and the per-GB fee covers access to Active Review, ECA tools, and Cecilia's AI features.$q$, $q$DISCO also offers professional project management services, billed separately at roughly $250 per hour, for teams that want hands-on help designing a review strategy. Because total cost depends on data volume and services selected, DISCO does not publish a single flat starting price; prospective customers request a custom quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('046d5368-1873-461f-9ac4-29a6afeb6d0a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Servers & Channels$q$, $q$Communities are organized into servers with dedicated text and voice channels for topic-based conversation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Voice & Video Calls$q$, $q$Low-latency voice chat, video calls, and screen sharing built for gaming and community use.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Stages & Activities$q$, $q$Stages support structured audio events; Activities let members play embedded mini-games inside voice channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Bots & API$q$, $q$A large ecosystem of third-party bots and a public API for moderation, music, games, and workflow automation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Discord Nitro$q$, $q$Premium subscription adding animated avatars, 4K streaming, larger uploads, and custom emoji anywhere.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Server Boosts$q$, $q$Community-funded upgrades that improve audio quality, emoji limits, and perks for an entire server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Threads & DMs$q$, $q$Threaded conversations and direct or group messaging alongside main channel discussions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Cross-Platform Apps$q$, $q$Native apps for Windows, macOS, Linux, iOS, and Android, plus a web browser client.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Free core functionality with no feature-gated messaging limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Low-latency voice and video well suited to gaming and live communities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Large bot and API ecosystem for deep customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Broad cross-platform availability (desktop, web, iOS, Android)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Not designed as a formal workplace collaboration tool like Slack or Teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Server discovery and organization can be overwhelming for large communities$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Moderation at scale relies heavily on third-party bots and volunteer moderators$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Some premium features (higher upload limits, 4K streaming) require a paid Nitro subscription$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Is Discord free to use?$q$, $q$Yes. Discord's core text, voice, and video chat features are free. Paid Nitro subscriptions add extra perks like larger file uploads and animated avatars.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Who founded Discord?$q$, $q$Discord was founded by Jason Citron and Stanislav Vishnevskiy and publicly released in May 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$What is Discord Nitro?$q$, $q$Nitro is Discord's paid subscription, available as Nitro Basic ($2.99/month) or full Nitro ($9.99/month), unlocking higher upload limits, 4K streaming, animated avatars, and Server Boosts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$What are Server Boosts?$q$, $q$Server Boosts are perks contributed by community members that upgrade a server's audio quality, emoji limits, and other features; Nitro subscribers receive free boosts each month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Is Discord only for gamers?$q$, $q$Discord started as a gaming chat app but is now used broadly by creators, open-source projects, study groups, and businesses, though gaming communities remain central to its user base.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$What platforms does Discord support?$q$, $q$Discord is available on Windows, macOS, Linux, iOS, and Android, plus a browser-based web client.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Gaming Communities$q$, $q$Guilds, clans, and friend groups use Discord for low-latency voice chat and coordination while playing games together.$q$, $q$Gamers and gaming clans$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Creator & Fan Communities$q$, $q$Streamers and content creators run Discord servers to engage fans, share updates, and build community around their content.$q$, $q$Content creators and streamers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Open-Source & Developer Communities$q$, $q$Open-source projects and developer groups use Discord servers for support channels, discussion, and collaboration.$q$, $q$Developers and open-source maintainers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["Unlimited text messages","Voice and video calls","Screen sharing","Group calls up to 25 participants"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Nitro Basic$q$, $q$$2.99/month ($29.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Larger file uploads","Custom emoji usable anywhere","Basic profile customization"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$Nitro$q$, $q$$9.99/month ($99.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["500MB file uploads","4K video streaming","Animated avatars","2 free Server Boosts monthly"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Discord is a free voice, video, and text communication platform organized into communities called servers, each divided into channels. Launched in May 2015 by Jason Citron and Stanislav Vishnevskiy after their game studio, Hammer & Chisel, struggled with unreliable voice-chat tools, Discord grew from a gaming-focused chat app into a general-purpose community platform used by millions of communities worldwide.$q$, $q$Headquartered in San Francisco, Discord has reported more than 200 million monthly active users at various points and roughly 90 million or more daily active users by late 2025, with founder Jason Citron stepping down as CEO in April 2025 in favor of gaming-industry veteran Humam Sakhnini.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Discord's core building blocks are servers made up of text channels, voice channels, threads, Stages for structured audio events, and Activities for embedded mini-games playable inside voice channels. The platform supports direct messages, group calls, screen sharing, and video calls across desktop, web, and mobile.$q$, $q$A large third-party bot and API ecosystem lets server owners add moderation, music, games, and automation. Premium Nitro subscriptions add animated avatars, larger file uploads, higher-quality video streaming, and Server Boosts that unlock perks for an entire community.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Discord's core chat, voice, and video features are free for everyone. Paid tiers are Nitro Basic at $2.99/month ($29.99/year) and full Nitro at $9.99/month ($99.99/year), the latter adding 4K streaming, 500MB uploads, animated avatars usable anywhere, and two free Server Boosts.$q$, $q$Server Boosts can also be purchased directly to upgrade a specific community's perks. Discord offers localized pricing across many countries and currencies, and annual billing saves roughly 17% versus paying monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
