INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b1dea31-abbd-42cc-a4cd-5b6154e0b8f7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Multi-Store Price Tracking$q$, $q$Monitors prices across 25+ built-in retailers including Amazon, eBay, Walmart, Costco, and AliExpress.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Browser Extension$q$, $q$Chrome extension for adding products to track directly from a retailer's product page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Multi-Channel Notifications$q$, $q$Sends price alerts via Ntfy, Telegram, or Gotify based on user-defined rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Custom & Community Stores$q$, $q$Supports unlimited custom store configurations, plus community-contributed integrations shared on GitHub.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Multi-User Support$q$, $q$A single self-hosted instance can serve multiple user accounts with admin-configurable link limits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Flexible Alert Rules$q$, $q$Set multiple rules per product for target price, percentage discount, lowest price in a time window, stock, and seller verification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Currency Conversion$q$, $q$Converts tracked prices into a user's preferred currency via a configurable currency API key.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Docker-Based Self-Hosting$q$, $q$Deployable via direct install, Docker, Docker Compose, or Portainer for home-lab and server environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Completely free with no subscription or licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Self-hosted, giving users full ownership and control of their tracking data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Broad store coverage plus support for unlimited custom and community stores$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Explicitly collects no analytics or telemetry data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Requires self-hosting and basic server/Docker knowledge; no managed cloud version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Browser extension is currently Chrome-focused with no confirmed dedicated mobile app$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Smaller community and less polish than commercial price-tracking tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Currency conversion requires configuring a separate third-party API key$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Is Discount Bandit free?$q$, $q$Yes. Discount Bandit is completely free, open-source software with no paid tiers or licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Do I need to self-host Discount Bandit?$q$, $q$Yes. There is no managed cloud version; you deploy it yourself via direct install, Docker, Docker Compose, or Portainer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Which stores does Discount Bandit support?$q$, $q$It has 25+ built-in retailer integrations including Amazon, eBay, Walmart, Costco, and AliExpress, plus support for unlimited custom and community-contributed stores.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$How do I get notified of price drops?$q$, $q$Discount Bandit sends alerts through Ntfy, Telegram, or Gotify based on rules you configure per product, such as a target price or percentage discount.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Does Discount Bandit collect my data?$q$, $q$No. The project states it does not collect data, use analytics, or send data anywhere other than the tracked retail websites.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Can multiple people use one Discount Bandit instance?$q$, $q$Yes. Discount Bandit supports multiple user accounts on a single self-hosted instance, with admin-configurable link limits per user.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Individual Deal Hunting$q$, $q$Shoppers track Amazon, eBay, and other retail prices to buy at the lowest observed price rather than checking pages manually.$q$, $q$Individual online shoppers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Shared Household Tracking$q$, $q$Families or roommates run a shared self-hosted instance with separate accounts to track different wish lists.$q$, $q$Households and small groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Privacy-Conscious Self-Hosting$q$, $q$Home-lab enthusiasts who already run Docker-based self-hosted infrastructure add Discount Bandit to avoid commercial extensions that track shopping behavior.$q$, $q$Self-hosting and privacy-focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$Self-Hosted$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited tracked products","Multi-user support","25+ built-in store integrations","Community store configurations","Docker-based deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Discount Bandit is a free, open-source, self-hosted price tracker built for people who want to monitor product prices without depending on a commercial browser extension or SaaS service. Maintained by a developer known as Cybrarist and distributed via GitHub, Docker Hub, and the Chrome Web Store, it pairs a self-hosted dashboard with a browser extension for adding products directly from a store's product page.$q$, $q$The project explicitly avoids collecting user data or using analytics, positioning itself as a privacy-first alternative for deal hunters and home-lab enthusiasts who want full control over their shopping-tracking data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Discount Bandit supports more than 25 built-in retailer integrations, including Amazon, eBay, Walmart, Costco, and AliExpress, plus unlimited custom stores and community-contributed store configurations for retailers not natively supported.$q$, $q$Notifications are delivered through Ntfy, Telegram, or Gotify based on rules users define per product, such as a target price, a percentage discount, the lowest price seen in a time window, stock changes, or seller verification status. The system supports multiple users on a single instance, with admin-configurable link limits per account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Discount Bandit is completely free and open source, with no paid tiers, subscriptions, or licensing fees. Users self-host the application, typically via Docker, Docker Compose, or Portainer, and bear only their own server hosting costs.$q$, $q$Because there is no managed cloud offering, all functionality — multi-user support, unlimited tracked products, and community store integrations — is included at no cost to anyone willing to run their own instance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09c39a74-1b42-4789-af73-47c7785446b4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Categories & Tags$q$, $q$Organizes discussions into structured categories and flexible tags for easy navigation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Trust Levels & Gamification$q$, $q$Reputation system with badges and likes that gradually grants more permissions to active community members.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Native Chat$q$, $q$Real-time chat feature alongside traditional threaded discussions, added in 2023.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$SSO Integration$q$, $q$Single sign-on via OAuth2, OpenID Connect, and SAML for enterprise identity providers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Discourse AI$q$, $q$First-party AI plugin suite adding topic summarization, sentiment analysis, smart replies, and AI moderation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Plugin & Theme Ecosystem$q$, $q$Dozens of official and community plugins plus customizable themes for extending functionality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$API & Webhooks$q$, $q$Full API and webhook access for custom integrations and automation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Self-Hosted Docker Deployment$q$, $q$Officially supported free self-hosting via Docker for full infrastructure control.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Fully open-source and free to self-host with no licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Modern, fast, chat-like interface built on Rails and Ember.js$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Highly extensible via plugins, themes, and a full API$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Founded and led by an experienced team with a track record (Stack Overflow)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Self-hosting requires server and Docker administration skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Hosted Business and Enterprise tiers can get expensive at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Steeper learning curve for non-technical community managers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Free hosted tier has fairly limited resource caps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Is Discourse free?$q$, $q$Yes, Discourse is free and open source to self-host. Managed hosting plans start with a limited free tier and paid plans from $100/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Who founded Discourse?$q$, $q$Discourse was founded in 2013 by Jeff Atwood, co-founder of Stack Overflow, along with Robin Ward and Sam Saffron.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$What license does Discourse use?$q$, $q$Discourse is released under a GPL-family open-source license, with source code freely available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Can I self-host Discourse instead of paying for hosting?$q$, $q$Yes. Discourse officially supports free self-hosting via Docker, giving organizations full control over infrastructure and data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Does Discourse support single sign-on?$q$, $q$Yes. Discourse supports SSO via OAuth2, OpenID Connect, and SAML, available on Business and Enterprise hosted plans or configurable when self-hosted.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$What is Discourse AI?$q$, $q$Discourse AI is a first-party plugin suite that adds AI-powered summarization, sentiment analysis, smart replies, and moderation assistance to a Discourse community.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Open-Source Project Forums$q$, $q$Open-source software projects use Discourse as a free, self-hosted community and support forum for users and contributors.$q$, $q$Open-source maintainers and communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$SaaS Customer & Developer Communities$q$, $q$Technology companies run Discourse as a branded support and discussion community for customers and developers.$q$, $q$SaaS and technology companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Interest-Based Online Communities$q$, $q$Hobbyist, gaming, and general-interest communities migrate from legacy forum software or closed social platforms to Discourse for more control and a modern experience.$q$, $q$Online community organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Free (Self-Hosted or Hosted Trial)$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["500k monthly page views","5GB storage","20k monthly emails","2 staff seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Pro$q$, $q$$100/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited members & chat","Unlimited categories/tags","Custom domain & themes","API/webhook access","15+ plugins","5 staff seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Business$q$, $q$$500/month$q$, $q$Monthly$q$, NULL, $q$["Advanced reporting & analytics","Automation & events","SSO (OpenID & OAuth2)","20+ additional plugins","15 staff seats","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Expert design & development services","99.9% uptime guarantee","GDPR & CCPA-compliant hosting","50+ plugins","Unlimited staff seats"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Discourse is an open-source community discussion and forum platform built by Civilized Discourse Construction Kit, Inc., founded in 2013 by Jeff Atwood (co-founder of Stack Overflow), Robin Ward, and Sam Saffron. Headquartered in El Cerrito, California, and operated as a fully remote company, Discourse combines a modern, chat-like real-time interface with the structure of a traditional threaded forum.$q$, $q$The platform is free and open source under a GPL-family license, self-hostable via Docker, and also available as managed hosting through tiered SaaS plans generating the company's primary revenue.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Discourse organizes discussions into categories and tags, uses trust levels and gamification to build community reputation, and added native real-time Chat in 2023 alongside its traditional threaded discussions. SSO via OAuth2, OpenID, and SAML supports enterprise identity integration.$q$, $q$An extensive plugin and theme ecosystem, full API and webhook access, and the first-party Discourse AI plugin suite (summarization, sentiment analysis, smart replies, AI moderation) round out the platform's extensibility.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Discourse is entirely free since the software is open source; organizations only pay for their own server infrastructure. Managed hosting starts with a limited free tier, then Pro at $100/month, Business at $500/month, and a custom-priced Enterprise tier.$q$, $q$Each hosted tier raises limits on monthly page views, storage, emails, staff seats, and AI feature credits, with Business and Enterprise adding advanced automation, SSO, more plugins, and priority support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b5b1e4-ac40-42b0-bab2-d22554c5ce08', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
