INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Visual Journey Builder$q$, $q$Design automated, multi-step messaging workflows triggered by user behavior or product events.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Broadcast Campaigns$q$, $q$Send one-off messages to segmented audiences alongside automated journeys.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$User Segmentation$q$, $q$Build targeted audience segments based on user properties and behavioral events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Omnichannel Delivery$q$, $q$Send messages via email, SMS, mobile push, WhatsApp, and Slack from a single platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Open-Source Self-Hosting$q$, $q$Fully open-source core deployable via Docker or Render at no licensing cost.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Integrations Library$q$, $q$Connects to common data and delivery tools such as Segment, Twilio, and SendGrid.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$API & SDK-First Design$q$, $q$Programmatic triggers for developer-led marketing and growth workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$White-Labeling (Enterprise)$q$, $q$Enterprise plans support white-labeling and embeddable components for platform builders.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Fully open-source with a genuine free self-hosted option$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Transparent, affordable entry pricing with clear usage-based overage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Developer-friendly, API/SDK-first architecture$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$No vendor lock-in; full data ownership when self-hosted$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Smaller integrations library and ecosystem than large incumbents like Braze$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Enterprise pricing is not publicly listed and requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Younger, smaller company with a less extensive support footprint$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Is Dittofeed free?$q$, $q$Yes, the self-hosted open-source core is free. Dittofeed also offers a managed Cloud Pro plan starting at $75/month with a 14-day free trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Can I self-host Dittofeed?$q$, $q$Yes. Dittofeed can be self-hosted via Docker or platforms like Render at no licensing cost, since the core platform is open source.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$What channels does Dittofeed support?$q$, $q$Dittofeed supports email, SMS, mobile push notifications, WhatsApp, and Slack for automated journeys and broadcast campaigns.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Who is Dittofeed for?$q$, $q$Dittofeed targets developer-led marketing and growth teams, particularly startups wanting an open-source alternative to platforms like Klaviyo, Braze, or Customer.io.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$How does Dittofeed's Cloud pricing scale?$q$, $q$Cloud Pro includes 10,000 monthly unique users for $75/month, with tiered per-user overage pricing decreasing as volume increases beyond that threshold.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Who founded Dittofeed?$q$, $q$Dittofeed was founded in 2022 by Chandler Craig and Maxwell Gurewitz, who went through Y Combinator's S22 batch.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Open-Source Alternative to Klaviyo/Customer.io$q$, $q$Startups migrate off expensive commercial engagement platforms to Dittofeed's open-source, self-hosted alternative.$q$, $q$Growth-stage startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Compliance-Driven Self-Hosting$q$, $q$Companies with strict data residency or compliance requirements self-host Dittofeed to keep customer data entirely in-house.$q$, $q$Regulated or security-conscious companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Lifecycle & Onboarding Journeys$q$, $q$Product and growth teams build automated onboarding, activation, and retention journeys triggered by product events.$q$, $q$Product and growth teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Self-Hosted$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Full open-source platform","Self-hosted via Docker or Render","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Cloud Pro$q$, $q$$75/month$q$, $q$Monthly$q$, NULL, $q$["10,000 monthly unique users included","Tiered per-user overage pricing","Full integrations library","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$Enterprise (Self-Hosted or Cloud)$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Multi-tenant advanced auth","White-labeling & embeddable components","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dittofeed is an open-source customer engagement platform for building omnichannel messaging journeys and broadcast campaigns across email, SMS, push, WhatsApp, and Slack. Founded in 2022 by Chandler Craig and Maxwell Gurewitz through Y Combinator's S22 batch, the Los Angeles-based company set out to build an open-source alternative to closed platforms like Klaviyo, Braze, and Customer.io.$q$, $q$Gurewitz's prior experience architecting messaging infrastructure at Braze directly informs Dittofeed's technical design, while the platform's fully public source code and self-hosting support give companies full ownership over customer data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dittofeed centers on a visual journey builder for automated, multi-step messaging workflows triggered by user behavior, plus a broadcast campaign feature for one-off sends and a segmentation engine for audience targeting. An integrations library connects to tools like Segment, Twilio, and SendGrid.$q$, $q$Being API and SDK-first, Dittofeed is built for developer-led growth teams that want to trigger messages programmatically from product events, while still offering a UI-based builder for marketers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source core is free with no licensing fee. Dittofeed's managed Cloud Pro plan costs $75/month for up to 10,000 monthly unique users, with tiered per-user overage pricing beyond that, plus a 14-day free trial.$q$, $q$Custom-priced Enterprise Self-Hosted and Enterprise Cloud licenses add multi-tenant auth, white-labeling, and priority support, and a separate Support Pro add-on offers dedicated implementation help.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c39707a3-e756-48c8-929c-f10fe278ae92', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
