INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Unified Conversation Timeline$q$, $q$Combines phone, email, chat, social, and form-based interactions into one continuous customer history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Mim AI Agent$q$, $q$Native AI agent designed to autonomously resolve customer inquiries, billed separately per conversation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Intelligent Routing & IVR$q$, $q$Routes phone and chat conversations intelligently, including interactive voice response for call handling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Knowledge Base$q$, $q$Built-in self-service knowledge base for customers and reference material for agents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Call Recording & Callback$q$, $q$Records calls for quality and training purposes and supports scheduled customer callbacks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$35+ Native Integrations$q$, $q$Pre-built integrations with ecommerce and marketing tools such as Shopify and Klaviyo.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$AI Co-Pilot & QA (Add-ons)$q$, $q$Optional generative-AI drafting/translation assistance and real-time quality assurance monitoring.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$SSO & Custom Roles (Prime)$q$, $q$Single sign-on, custom user roles, and multi-organization support on the top-tier plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$True unified omnichannel conversation view, not just multi-channel ticketing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Native AI agent (Mim) built into the core platform rather than bolted on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Strong ecommerce/Shopify-focused integrations for DTC brands$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Transparent, publicly published per-agent pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Per-agent pricing can become expensive for larger support teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Advanced AI and automation features are gated to higher (Ultimate/Prime) tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Mim AI usage is billed separately per conversation, adding a variable cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Smaller company and support footprint than larger competitors like Zendesk or Intercom$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$What is Dixa used for?$q$, $q$Dixa is used as a customer service and helpdesk platform that unifies phone, email, chat, social, and form-based support into one conversation view for support teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$How much does Dixa cost?$q$, $q$Dixa's published plans start at €89 per agent per month (Growth), rising to €139 (Ultimate) and €179 (Prime), with roughly a 20% discount for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$What is Mim?$q$, $q$Mim is Dixa's native AI agent designed to autonomously resolve customer inquiries; it is billed separately at a flat usage-based rate of roughly €0.35 per conversation.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Does Dixa integrate with Shopify?$q$, $q$Yes. Dixa offers native integrations with Shopify, Klaviyo, and more than 35 other ecommerce and marketing tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Who founded Dixa?$q$, $q$Dixa was founded in 2015 in Copenhagen by Mads Fosselius, Krisztian Tabori, Jakob Nederby Nielsen, and Jacob Vous Petersen.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$How much funding has Dixa raised?$q$, $q$Dixa has raised approximately $158 to $164 million across multiple rounds, including a $105 million Series C led by General Atlantic in 2021.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Ecommerce & DTC Support$q$, $q$Ecommerce and direct-to-consumer brands use Dixa to manage high-volume support across phone, chat, and email with native Shopify integration.$q$, $q$Ecommerce and DTC brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Omnichannel Contact Center$q$, $q$Mid-market companies consolidate phone, chat, email, and social support into a single Dixa workspace instead of separate point tools.$q$, $q$Mid-market customer service teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$AI-Automated First-Line Support$q$, $q$Enterprises deploy Dixa's Mim AI agent to automatically resolve common inquiries before escalating to human agents.$q$, $q$Enterprise support operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Growth$q$, $q$€89/agent/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["Contact center (phone, email, chat, social, forms)","Knowledge base","Mim AI agent","Intelligent routing & IVR","Call recording & callback","35+ native integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Ultimate$q$, $q$€139/agent/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["Everything in Growth","Routing with external data","Knowledge-centered service AI","Standard AI intent detection","Advanced automations & skills-based routing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$Prime$q$, $q$€179/agent/month$q$, $q$Monthly or annual (20% off annual)$q$, NULL, $q$["Everything in Ultimate","SSO","Advanced AI intent detection","Advanced insights AI","Custom user roles & multiple organizations","Enterprise API limits"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dixa is a cloud-based customer service platform founded in 2015 in Copenhagen, Denmark, by Mads Fosselius, Krisztian Tabori, Jakob Nederby Nielsen, and Jacob Vous Petersen. The platform unifies phone, email, chat, social, and form-based support into a single customer conversation timeline rather than treating each channel as a separate ticket queue.$q$, $q$Dixa has raised roughly $158 to $164 million across multiple funding rounds, including a $105 million Series C led by General Atlantic in 2021, and now serves more than 1,000 ecommerce and DTC brands across 42 countries from offices in Copenhagen and London.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dixa's core workspace combines intelligent phone routing and IVR, call recording, live chat, email, and social messaging with a built-in knowledge base and SLA tracking, plus native integrations with 35+ tools including Shopify and Klaviyo.$q$, $q$Mim, Dixa's AI agent, is built into the platform to autonomously handle customer inquiries, alongside optional AI Co-Pilot, quality assurance, and voice transcription add-ons for teams that want deeper AI-assisted support tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dixa publishes three per-agent, per-month tiers: Growth at €89, Ultimate at €139, and Prime at €179, each billed monthly or annually with roughly a 20% discount for annual billing. Higher tiers unlock deeper AI intent detection, SSO, custom roles, and higher API limits.$q$, $q$Mim, the AI agent, is billed separately on a flat usage-based rate of roughly €0.35 per conversation, and additional add-ons such as AI Co-Pilot, quality assurance, and voice transcription are available at extra cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a056723-ee4b-46ab-988f-3d80d7a96c4e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Contact & Company Management$q$, $q$Centralized records for contacts and companies tied to sales activity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Sales Pipeline & Deal Tracking$q$, $q$Track leads, opportunities, and deals through a configurable sales pipeline.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Task & Project Management$q$, $q$Manage tasks and projects linked to sales and customer-facing activities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Built-In Email Marketing$q$, $q$Mass mailing and email marketing capabilities built directly into the CRM.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Analytics & Reporting$q$, $q$Dashboards and reports for tracking sales performance and pipeline health.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Role-Based Access Control$q$, $q$Configurable permissions for different user types and teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Email & VoIP Integration$q$, $q$Log outbound calls and emails automatically against contacts and deals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$20+ Language Support$q$, $q$Interface and documentation available in more than 20 languages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Completely free with no per-user or licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Full self-hosted data ownership avoids vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Deep customization potential for Python/Django developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Production-stable and used in real business deployments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Requires Django/Python expertise to install, customize, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$No official managed cloud or SaaS hosting option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$AGPL-3.0 license requires open-sourcing modifications used as a network service$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Smaller support community than commercial CRMs like HubSpot or Salesforce$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Is Django-CRM really free?$q$, $q$Yes. Django-CRM is fully open source with no license fees or per-user charges; you only pay for your own hosting infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Do I need coding skills to use Django-CRM?$q$, $q$Basic Django/Python knowledge is recommended for installation, customization, and maintenance, since there is no managed hosting option.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$What license does Django-CRM use?$q$, $q$Django-CRM is released under the GNU Affero General Public License v3 (AGPL-3.0).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Can Django-CRM send marketing emails?$q$, $q$Yes. It includes built-in mass email marketing and mailing capabilities alongside its core CRM features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$How is this different from other 'Django CRM' projects on GitHub?$q$, $q$This project, maintained under the DjangoCRM GitHub organization, is distinct from similarly named projects like MicroPyramid's Django-CRM, which is a separate codebase built with Django REST Framework and SvelteKit.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Does Django-CRM offer cloud hosting?$q$, $q$No. Django-CRM does not offer an official managed cloud or SaaS version; it is deployed as self-hosted software.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Developer-Led CRM Deployments$q$, $q$Python/Django development shops adopt Django-CRM as a self-hosted CRM they can extend to match internal workflows.$q$, $q$Python and Django developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Cost-Conscious Small Businesses$q$, $q$Small businesses and freelancers avoid per-seat SaaS CRM costs by self-hosting Django-CRM instead.$q$, $q$Small businesses and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Data-Ownership-Focused Teams$q$, $q$Organizations with compliance or data-residency needs self-host Django-CRM to keep full ownership of customer data.$q$, $q$Compliance-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited users","Full source code access","AGPL-3.0 license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Django-CRM is a free, open-source customer relationship management system built directly on the Django web framework and its admin interface, maintained primarily by Vadym Kharchenko and distributed via the DjangoCRM GitHub organization under the AGPL-3.0 license.$q$, $q$The project describes itself as production and stable, having been used in real business deployments for years, and is distinct from other similarly named 'Django-CRM' projects on GitHub, such as the separate MicroPyramid project built with Django REST Framework and SvelteKit.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Django-CRM covers contact and company management, sales pipeline and deal tracking, task and project management, built-in mass email marketing, analytics and reporting, role-based access control, and integrated email/VoIP logging, with support for more than 20 languages.$q$, $q$By building on Django's own admin framework rather than a custom UI layer, the project stays lean and highly customizable for developers already familiar with Python and Django.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Django-CRM is completely free with no license fees and no per-user costs, since it is fully open source under the AGPL-3.0 license. There is no official managed cloud offering; every deployment is self-hosted.$q$, $q$Organizations only bear the cost of their own hosting infrastructure and the developer time needed to install, configure, and maintain the system, in exchange for full ownership of their code and customer data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb776dbd-be66-4afc-b3df-cfd58e6b6dd3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Guided One-Question Interviews$q$, $q$Presents users with one question at a time to reach an end point such as a document or application.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$YAML + Python Authoring$q$, $q$Interviews are written as YAML blocks combined with Python code blocks for full logical flexibility.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Automated Document Assembly$q$, $q$Generates Word and PDF documents from interview answers using Markdown and Jinja2 templating.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$API Integration$q$, $q$Interviews can call external APIs to submit applications or retrieve data during the workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Reusable Packages$q$, $q$Interview logic is packaged and shared via GitHub for reuse across docassemble servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Docker & Cloud Deployment$q$, $q$Deployable locally, via Docker, or on cloud providers such as AWS and DigitalOcean.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Multi-Server Clustering$q$, $q$Supports clustered, multi-server deployments for higher-volume production use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$MIT-Licensed Source$q$, $q$Fully open-source codebase under the permissive MIT license, with CC BY 3.0 documentation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Extremely flexible - can automate documents, workflows, or informational tools, not just legal use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Strong, established community in the legal aid and access-to-justice space$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Reusable Package ecosystem shared openly on GitHub$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Steep learning curve requiring YAML and Python knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$No official managed hosting from the project itself; self-hosting or third-party hosting required$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Interface feels more utilitarian than modern commercial alternatives like Gavel$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Documentation assumes a technical background, less approachable for non-developers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Is docassemble free to use?$q$, $q$Yes. Docassemble's source code is released under the MIT license and is completely free to download, run, and modify.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Do I need to know how to code to use docassemble?$q$, $q$Building interviews requires familiarity with YAML and basic Python, so some technical skill is generally necessary.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$What can docassemble create besides documents?$q$, $q$Interviews can submit applications, store structured data, call external APIs, or simply present information, in addition to generating Word or PDF documents.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$How is docassemble hosted?$q$, $q$Docassemble can be run locally or deployed via Docker to cloud providers such as AWS or DigitalOcean; there is no official managed hosting service from the project itself, though third-party providers offer hosting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Who created docassemble?$q$, $q$Docassemble was created by Jonathan Pyle, a Philadelphia lawyer and programmer, first announced in 2015 at the Legal Services Corporation's TIG conference.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$What license does docassemble use?$q$, $q$Docassemble's code is released under the MIT license, and its documentation is released under a Creative Commons Attribution (CC BY 3.0) license.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Legal Aid Self-Service Tools$q$, $q$Legal aid organizations build guided interviews that help low-income clients complete forms and understand their legal options without a lawyer present.$q$, $q$Legal aid organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Court & Government Form Automation$q$, $q$Courts and government agencies use docassemble to automate public-facing forms and applications.$q$, $q$Courts and government agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Law Firm Document Automation$q$, $q$Law firms and in-house legal teams automate routine contract and document generation to save attorney time.$q$, $q$Law firms and in-house legal teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["MIT-licensed source code","Self-hosted deployment (local, Docker, or cloud)","Unlimited interviews and Packages","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Docassemble is a free, open-source expert-system platform for building guided interviews that present one question at a time and can generate documents, submit applications, or deliver tailored information. Created by Philadelphia lawyer-programmer Jonathan Pyle and first announced in 2015 at the Legal Services Corporation's TIG conference, it grew out of the access-to-justice community and remains widely used across legal aid organizations, courts, and law school clinics.$q$, $q$Despite its name, docassemble interviews do not need to produce a document at all; they can submit applications, store data, call external APIs, or simply inform the user, making the platform closer to a general guided-workflow engine than a narrow document generator.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Interviews are authored as YAML blocks combined with Python code blocks and Jinja2-style templating for document output, giving developers full programming flexibility alongside a declarative interview format. Reusable interview logic is packaged and shared via GitHub as installable Packages.$q$, $q$Docassemble supports local development, Docker-based deployment, and multi-server clustered configurations for scale, along with API integration for connecting interviews to external systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Docassemble's source code is free under the MIT license, and its documentation is available under a CC BY 3.0 license, with no cost to download, run, or modify the software. There is no official managed hosting service from the project itself.$q$, $q$A surrounding ecosystem of independent consultants and hosting providers offers paid implementation, customization, and hosting services built on top of the free open-source core for organizations that want professional support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c386a7f9-0f7e-468a-84bc-c61cc73cf1a4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
